//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: **Linked styles (paragraph+character link pairing)** — ECMA-376 / ISO
//! 29500-1 §17.7.4.6 `w:link`, with MS-OI29500 §2.1.235 implementation notes.
//!
//! Each `#[test]` encodes one declarative TestSpec mined from the OOXML / Word
//! specifications. A **FAIL here is a real Word-compliance gap in stemma** — the
//! engine diverges from how Microsoft Word consumes the markup. Do NOT weaken an
//! assertion to make it pass; a failing assertion is exactly the finding the
//! sweep is hunting for. Fix the engine (or, if the test encodes the wrong
//! expectation, fix the test against the spec), never the symptom.
//!
//! Methodology note: `w:link` pairing is a **consumption** rule (the link is
//! "ignored" on read, never rewritten on save). stemma round-trips untouched
//! content byte-verbatim, so these tests assert on the READ side
//! (`opens-clean` + `read_rejected()/read_accepted().to_text()`), never as
//! `xmlOmits` on the verbatim-preserved `w:link` markup.

use stemma::ExportOptions;
use stemma::api::{Document, validate};

// ─── Prelude / plumbing ──────────────────────────────────────────────────────

/// Build a minimal valid `.docx`. `body_xml` is the inner content of
/// `<w:body>…</w:body>`. `extra_parts` are additional package parts (e.g.
/// `word/styles.xml`) added with the right content-type override + relationship.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content types: base defaults + the document override, plus an override per
    // extra part (mapping the well-known part names to their content types).
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part, _) in extra_parts {
        let ct = content_type_for(part);
        overrides.push_str(&format!(
            r#"<Override PartName="/{part}" ContentType="{ct}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // document.xml.rels: one relationship per extra part (so styles.xml is
    // discoverable from the main document part).
    let mut doc_rel_entries = String::new();
    for (i, (part, _)) in extra_parts.iter().enumerate() {
        let rid = format!("rIdExtra{}", i + 1);
        let rel_type = rel_type_for(part);
        // Target is relative to word/ (the document part's folder).
        let target = part.strip_prefix("word/").unwrap_or(part);
        doc_rel_entries.push_str(&format!(
            r#"<Relationship Id="{rid}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rel_entries}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

fn content_type_for(part: &str) -> &'static str {
    match part {
        "word/styles.xml" => {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        }
        "word/numbering.xml" => {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        }
        other => panic!("unknown extra part content type for {other}"),
    }
}

fn rel_type_for(part: &str) -> &'static str {
    match part {
        "word/styles.xml" => {
            "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles"
        }
        "word/numbering.xml" => {
            "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering"
        }
        other => panic!("unknown extra part rel type for {other}"),
    }
}

/// Unzip and return `word/document.xml` of a `.docx` byte stream.
#[allow(dead_code)]
fn document_xml_of(docx: &[u8]) -> String {
    let archive = stemma::docx::DocxArchive::read(docx).expect("read archive");
    String::from_utf8(
        archive
            .get("word/document.xml")
            .expect("document.xml present")
            .to_vec(),
    )
    .expect("utf8")
}

/// Parse -> serialize -> return `word/document.xml`. Reflects stemma's
/// serializer output (verbatim-preserving for untouched content).
#[allow(dead_code)]
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// True when `validate` reports no errors (opens-clean in Word terms).
fn opens_clean(bytes: &[u8]) -> Result<(), String> {
    let report = validate(bytes);
    if report.ok && report.issues.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "validation issues: {:?}",
            report
                .issues
                .iter()
                .map(|i| format!("[{:?}] {}", i.code, i.message))
                .collect::<Vec<_>>()
        ))
    }
}

fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
}

fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
}

