// ─── Tests ───────────────────────────────────────────────────────────────────

#[test]
fn link_para_to_paragraph_style_cross_type_ignored_opens_clean() {
    let body = r#"<w:p><w:pPr><w:pStyle w:val="BodyA"/></w:pPr><w:r><w:t>cross type link</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", STYLES_PARA_TO_PARA)]);

    opens_clean(&b).unwrap_or_else(|e| {
        panic!(
            "ISO 29500-1 §17.7.4.6 / ECMA-376 §17.7.4.6 — a paragraph-style w:link \
         pointing at another PARAGRAPH style 'shall be ignored'; an ignored \
         (not rejected) cross-type link is tolerated, so Word opens without \
         repair. Got {e}"
        )
    });

    assert_eq!(
        reject_text(&b).trim(),
        "cross type link",
        "ISO 29500-1 §17.7.4.6 — a link is purely a style-pairing hint; ignoring \
         it changes no document text, so reject-all (no tracked changes) yields \
         the original run text verbatim."
    );
}

#[test]
fn link_to_nonexistent_styleid_ignored_opens_clean() {
    let body = r#"<w:p><w:pPr><w:pStyle w:val="Quote"/></w:pPr><w:r><w:t>dangling link</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", STYLES_DANGLING_PARA)]);

    opens_clean(&b).unwrap_or_else(|e| {
        panic!(
            "ISO 29500-1 §17.7.4.6 / ECMA-376 §17.7.4.6 — a w:link whose val names a \
         styleId no style defines 'shall be ignored'; a dangling link degrades \
         to a no-op, so Word opens without repair (parallel to the dangling \
         numStyleLink no-op). Got {e}"
        )
    });

    assert_eq!(
        reject_text(&b).trim(),
        "dangling link",
        "ISO 29500-1 §17.7.4.6 — ignoring the dead link leaves the run text \
         unchanged; with no tracked changes, reject-all returns the original text."
    );
}

#[test]
fn char_style_link_to_character_style_cross_type_ignored_opens_clean() {
    let body = r#"<w:p><w:r><w:rPr><w:rStyle w:val="Emphasis"/></w:rPr><w:t>char cross type</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", STYLES_CHAR_TO_CHAR)]);

    opens_clean(&b).unwrap_or_else(|e| {
        panic!(
            "ISO 29500-1 §17.7.4.6 / ECMA-376 §17.7.4.6 — a character-style w:link \
         must refer to a paragraph style 'or this element shall be ignored'; a \
         char->char link is the mirror cross-type mismatch Word ignores rather \
         than refusing the file. Got {e}"
        )
    });

    assert_eq!(
        reject_text(&b).trim(),
        "char cross type",
        "ISO 29500-1 §17.7.4.6 / §17.7.9 — ignoring the cross-type link does not \
         alter run text; with no tracked changes, reject-all returns the original."
    );
}

#[test]
fn char_style_without_link_not_part_of_pairing_opens_clean() {
    let body = r#"<w:p><w:r><w:rPr><w:rStyle w:val="Loner"/></w:rPr><w:t>no link half</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", STYLES_CHAR_NO_LINK_HALF)]);

    opens_clean(&b).unwrap_or_else(|e| {
        panic!(
            "ISO 29500-1 §17.7.4.6 / §17.7.9 — 'A style element without a child link \
         element is not part of a linked style pairing'; a standalone char style \
         applied via rStyle (even with another style linking TO it) is a normal, \
         valid construct that Word opens without repair. Got {e}"
        )
    });

    assert_eq!(
        reject_text(&b).trim(),
        "no link half",
        "ISO 29500-1 §17.7.4.6 / §17.7.9 — pairing membership affects only \
         formatting, not text; reject-all (no tracked changes) returns the \
         original run text."
    );
}

#[test]
fn para_link_to_nonexistent_styleid_ignored_opens_clean() {
    let body = r#"<w:p><w:pPr><w:pStyle w:val="LinkedPara"/></w:pPr><w:r><w:t>Linked paragraph with dangling link.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", STYLES_PARA_DANGLING_CHAR)]);

    opens_clean(&b).unwrap_or_else(|e| {
        panic!(
            "ISO 29500-1 §17.7.4.6 / MS-OI29500 §2.1.235 — a w:link to a styleId no \
         style defines 'shall be ignored'; the I-XREF-001 check scopes only to \
         content references (pStyle/rStyle), NOT w:link targets in styles.xml, so \
         a dangling link MUST NOT be flagged as a missing-style error. Got {e}"
        )
    });
}

