#[test]
fn duplicate_link_to_same_style_last_wins_opens_clean() {
    let body = r#"<w:p><w:pPr><w:pStyle w:val="LinkedPara"/></w:pPr><w:r><w:t>Two char styles both link to this paragraph style.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", STYLES_DUP_LINK)]);

    opens_clean(&b).unwrap_or_else(|e| {
        panic!(
            "MS-OI29500 §2.1.235 / ISO 29500-1 §17.7.4.6 — 'Word ignores all but the \
         last link to a given style.' Two char styles linking to the same \
         paragraph style is not an error; the ambiguous-link package is tolerated \
         and opens without repair, so the validator must report no errors. Got {e}"
        )
    });
}

