#[test]
fn para_link_to_paragraph_style_is_cross_type_ignored() {
    let body = r#"<w:p><w:pPr><w:pStyle w:val="LinkedPara"/></w:pPr><w:r><w:t>linked para text</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", STYLES_PARA_TO_PARA_RICH)]);

    opens_clean(&b).unwrap_or_else(|e| {
        panic!(
            "ISO 29500-1 §17.7.4.6 / ECMA-376 §17.7.4.6 — a para->para link is \
         ignored (not honored, not an error); Word opens such a file without \
         repair, so stemma's validator must report no errors. Got {e}"
        )
    });

    assert_eq!(
        accept_text(&b).trim(),
        "linked para text",
        "ISO 29500-1 §17.7.4.6 — the ignored cross-type link must not alter \
         document text; the paragraph still resolves to its own style, so \
         read-side (accept-all) text is unaffected."
    );
}

